example.code:
interface ButtonProps { $variant?: 'primary' | 'secondary'; $size?: 'sm' | 'md' | 'lg'; }

const Button = styled.button<ButtonProps>`
  ${({ $size = 'md' }) => sizes[$size]}
  ${({ $variant = 'primary', theme }) => variants($variant, theme)}
`;

// Usage — $ props not forwarded to <button>
<Button $variant="primary" $size="lg">Click</Button>

// Without $: variant="primary" is forwarded to <button variant="primary"> — invalid HTML
const Button = styled.button<{ variant?: string }>``;
<Button variant="primary">Click</Button>
